      const vehicle = new Vehicle(0, 400, 30, 1, 33.3);
      engine.road.lanes[1].addVehicle(vehicle);
      engine.addIncident(makeIncident({ positionX: 500, lanesBlocked: [1], duration: 2, startTime: 0 }));

