it('high politeness prevents lane change that low politeness allows', () => {
  // Deterministic setup: fast vehicle behind slow leader, follower in target lane
  const baseParams = makeParams({ laneCount: 3, spawnRate: 0 });

  // With low politeness: should change lane
  const lowEngine = new SimulationEngine({ ...baseParams, politenessFactor: 0 });
  const slowL = new Vehicle(0, 200, 15, 1, 15);
  const fastL = new Vehicle(1, 170, 30, 1, 33.3);
  const followerL = new Vehicle(2, 120, 28, 0, 33.3);
  lowEngine.road.lanes[1].addVehicle(slowL);
  lowEngine.road.lanes[1].addVehicle(fastL);
  lowEngine.road.lanes[0].addVehicle(followerL);

  let lowChanged = false;
  for (let i = 0; i < 300; i++) {
    lowEngine.step(baseParams.dt);
    if (fastL.laneIndex !== 1) { lowChanged = true; break; }
  }

  // With very high politeness: should NOT change (disadvantage to follower outweighs)
  const highEngine = new SimulationEngine({ ...baseParams, politenessFactor: 100 });
  const slowH = new Vehicle(0, 200, 15, 1, 15);
  const fastH = new Vehicle(1, 170, 30, 1, 33.3);
  const followerH = new Vehicle(2, 120, 28, 0, 33.3);
  // Block lane 2 with a close follower too
  const followerH2 = new Vehicle(3, 120, 28, 2, 33.3);
  highEngine.road.lanes[1].addVehicle(slowH);
  highEngine.road.lanes[1].addVehicle(fastH);
  highEngine.road.lanes[0].addVehicle(followerH);
  highEngine.road.lanes[2].addVehicle(followerH2);

  let highChanged = false;
  for (let i = 0; i < 300; i++) {
    highEngine.step(baseParams.dt);
    if (fastH.laneIndex !== 1) { highChanged = true; break; }
  }

  expect(lowChanged).toBe(true);
  expect(highChanged).toBe(false);
});

