    const params = makeParams({ laneCount: 1, spawnRate: 3 });
    const engine = new SimulationEngine(params);

    for (let i = 0; i < 500; i++) {
      engine.step(params.dt);
      for (const v of engine.road.getAllVehicles()) {
        expect(v.speed).toBeGreaterThanOrEqual(0);
