 15→function speedToRgb(
 16→  speed: number,
 17→  maxSpeed: number,
 18→): [number, number, number] {
 19→  const ratio = clamp(maxSpeed === 0 ? 0 : speed / maxSpeed, 0, 1);
 20→  // Red → Yellow → Green
 21→  let r: number, g: number, b: number;
 22→  if (ratio <= 0.5) {
 23→    const t = ratio / 0.5;
 24→    r = 220;
 25→    g = Math.round(50 + t * 170);
 26→    b = 30;
 27→  } else {
 28→    const t = (ratio - 0.5) / 0.5;
 29→    r = Math.round(220 - t * 180);
 30→    g = Math.round(220 - t * 20);
 31→    b = Math.round(30 + t * 60);
 32→  }
 33→  return [r, g, b];
 34→}
 35→
 36→export function SpeedHeatmap({
 37→  history,
 38→  maxSpeed,
 39→  width = 600,
