}

import { useRef, useEffect } from 'react';
import { clamp } from '../utils/math';
import type { RoadSegmentData } from '../types';

interface SpeedHeatmapProps {
  history: RoadSegmentData[][];
  maxSpeed: number;
  width?: number;
  height?: number;
}

const LABEL_LEFT = 40;
const LABEL_BOTTOM = 20;

function speedToRgb(
  speed: number,
  maxSpeed: number,
): [number, number, number] {
  const ratio = clamp(maxSpeed === 0 ? 0 : speed / maxSpeed, 0, 1);
  // Red → Yellow → Green
  let r: number, g: number, b: number;
  if (ratio <= 0.5) {
    const t = ratio / 0.5;
    r = 220;
    g = Math.round(50 + t * 170);
    b = 30;
  } else {
    const t = (ratio - 0.5) / 0.5;
    r = Math.round(220 - t * 180);
    g = Math.round(220 - t * 20);
    b = Math.round(30 + t * 60);
  }
  return [r, g, b];
}

export function SpeedHeatmap({
  history,
  maxSpeed,
  width = 600,
  height = 200,
}: SpeedHeatmapProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const plotW = width - LABEL_LEFT;
    const plotH = height - LABEL_BOTTOM;

    canvas.width = width;
    canvas.height = height;

    // Clear
    ctx.fillStyle = '#1f2937';
    ctx.fillRect(0, 0, width, height);

    if (history.length === 0) return;

    const segmentCount = history[0].length;
    const rowCount = Math.min(history.length, plotH);
    const cellW = plotW / segmentCount;
    const cellH = plotH / rowCount;

    // Draw rows: newest at bottom
    const startIdx = Math.max(0, history.length - rowCount);
    for (let row = 0; row < rowCount; row++) {
      const dataRow = history[startIdx + row];
      const y = plotH - (row + 1) * cellH;

      for (let col = 0; col < dataRow.length; col++) {
        const [r, g, b] = speedToRgb(dataRow[col].averageSpeed, maxSpeed);
        ctx.fillStyle = `rgb(${r},${g},${b})`;
        ctx.fillRect(LABEL_LEFT + col * cellW, y, Math.ceil(cellW), Math.ceil(cellH));
      }
    }

    // Axis labels
    ctx.fillStyle = '#9ca3af';
    ctx.font = '10px sans-serif';
    ctx.textAlign = 'center';

    // X axis: position labels
    const segLen = history[0]?.[0] ? 100 : 1; // segment length
    for (let i = 0; i <= segmentCount; i += Math.max(1, Math.floor(segmentCount / 5))) {
      const x = LABEL_LEFT + i * cellW;
      ctx.fillText(`${i * segLen}`, x, height - 4);
    }

    // Y axis: time labels
    ctx.textAlign = 'right';
    const sampleInterval = 0.5;
    for (let row = 0; row < rowCount; row += Math.max(1, Math.floor(rowCount / 5))) {
      const y = plotH - row * cellH;
      const timeAgo = row * sampleInterval;
      ctx.fillText(`-${timeAgo.toFixed(0)}s`, LABEL_LEFT - 4, y + 3);
    }

    // Axis titles
    ctx.fillStyle = '#6b7280';
    ctx.font = '10px sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('Position (m)', LABEL_LEFT + plotW / 2, height - 1);
  }, [history, maxSpeed, width, height]);

  return (
    <div className="bg-gray-800 rounded-lg p-3">
      <h3 className="text-sm text-gray-400 mb-2">
        Speed Heatmap (Space-Time)
      </h3>
      <canvas ref={canvasRef} className="w-full" style={{ imageRendering: 'pixelated' }} />
    </div>
  );
}

import { useState } from 'react';
import type { SimulationParams } from '../types';

interface ControlPanelProps {
  params: SimulationParams;
  onParamChange: (params: Partial<SimulationParams>) => void;
  onReset: () => void;
}

interface SliderRowProps {
  label: string;
  value: number;
  min: number;
  max: number;
  step: number;
  display?: (v: number) => string;
  onChange: (v: number) => void;
}

function SliderRow({ label, value, min, max, step, display, onChange }: SliderRowProps) {
  return (
    <div className="mb-2">
      <div className="flex justify-between text-xs mb-0.5">
        <span className="text-gray-400">{label}</span>
        <span className="text-gray-300 font-mono">
          {display ? display(value) : value.toFixed(step < 1 ? 1 : 0)}
        </span>
      </div>
      <input
        type="range"
        min={min}
        max={max}
        step={step}
        value={value}
        onChange={(e) => onChange(parseFloat(e.target.value))}
        className="w-full h-1.5 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
      />
    </div>
  );
}

interface SectionProps {
  title: string;
  defaultOpen?: boolean;
  children: React.ReactNode;
}

function Section({ title, defaultOpen = true, children }: SectionProps) {
  const [open, setOpen] = useState(defaultOpen);
  return (
    <div className="mb-3">
      <button
        onClick={() => setOpen(!open)}
        className="flex items-center justify-between w-full text-xs font-semibold text-gray-300 uppercase tracking-wider mb-1"
      >
        {title}
        <span className="text-gray-500">{open ? '−' : '+'}</span>
      </button>
      {open && <div className="pl-1">{children}</div>}
    </div>
  );
}

export function ControlPanel({ params, onParamChange, onReset }: ControlPanelProps) {
  return (
    <div className="bg-gray-800 border border-gray-700 rounded-lg p-3 text-sm w-64 overflow-y-auto max-h-[calc(100vh-120px)]">
      <div className="flex items-center justify-between mb-3">
        <h2 className="text-sm font-bold text-gray-200">Parameters</h2>
        <button
          onClick={onReset}
          className="text-xs bg-gray-700 hover:bg-gray-600 text-gray-300 px-2 py-0.5 rounded"
        >
          Reset
        </button>
      </div>

      <Section title="IDM (Car-Following)">
        <SliderRow
          label="Desired Speed"
          value={params.desiredSpeed}
          min={10}
          max={50}
          step={0.5}
          display={(v) => `${(v * 3.6).toFixed(0)} km/h`}
          onChange={(v) => onParamChange({ desiredSpeed: v })}
        />
        <SliderRow
          label="Time Headway"
          value={params.timeHeadway}
          min={0.5}
          max={3.0}
          step={0.1}
          display={(v) => `${v.toFixed(1)} s`}
          onChange={(v) => onParamChange({ timeHeadway: v })}
        />
        <SliderRow
          label="Max Acceleration"
          value={params.maxAcceleration}
          min={0.3}
          max={3.0}
          step={0.1}
          display={(v) => `${v.toFixed(1)} m/s²`}
          onChange={(v) => onParamChange({ maxAcceleration: v })}
        />
        <SliderRow
          label="Comfort Decel"
          value={params.comfortDeceleration}
          min={1.0}
          max={5.0}
          step={0.1}
          display={(v) => `${v.toFixed(1)} m/s²`}
          onChange={(v) => onParamChange({ comfortDeceleration: v })}
        />
        <SliderRow
          label="Minimum Gap"
          value={params.minimumGap}
          min={1.0}
          max={5.0}
          step={0.1}
          display={(v) => `${v.toFixed(1)} m`}
          onChange={(v) => onParamChange({ minimumGap: v })}
        />
      </Section>

      <Section title="MOBIL (Lane Change)" defaultOpen={false}>
        <SliderRow
          label="Politeness"
          value={params.politenessFactor}
          min={0}
          max={1.0}
          step={0.05}
          display={(v) => v.toFixed(2)}
          onChange={(v) => onParamChange({ politenessFactor: v })}
        />
        <SliderRow
          label="Change Threshold"
          value={params.changingThreshold}
          min={0}
          max={1.0}
          step={0.05}
          display={(v) => `${v.toFixed(2)} m/s²`}
          onChange={(v) => onParamChange({ changingThreshold: v })}
        />
        <SliderRow
          label="Safe Deceleration"
          value={params.safeDeceleration}
          min={2.0}
          max={8.0}
          step={0.5}
          display={(v) => `${v.toFixed(1)} m/s²`}
          onChange={(v) => onParamChange({ safeDeceleration: v })}
        />
      </Section>

      <Section title="Road & Traffic">
        <div className="mb-2">
          <div className="flex justify-between text-xs mb-0.5">
            <span className="text-gray-400">Lane Count</span>
            <span className="text-gray-300 font-mono">{params.laneCount}</span>
          </div>
          <select
            value={params.laneCount}
            onChange={(e) => onParamChange({ laneCount: parseInt(e.target.value) })}
            className="w-full bg-gray-700 text-white text-xs px-2 py-1 rounded border border-gray-600"
          >
            {[2, 3, 4, 5].map((n) => (
              <option key={n} value={n}>
                {n} lanes
              </option>
            ))}
          </select>
        </div>
        <SliderRow
          label="Spawn Rate"
          value={params.spawnRate}
          min={0.1}
          max={3.0}
          step={0.1}
          display={(v) => `${v.toFixed(1)} veh/s`}
          onChange={(v) => onParamChange({ spawnRate: v })}
        />
      </Section>
