export interface SimulationParams {
  // IDM
  desiredSpeed: number;          // v0, m/s
  timeHeadway: number;           // T, seconds
  maxAcceleration: number;       // a, m/s²
  comfortDeceleration: number;   // b, m/s²
  minimumGap: number;            // s0, meters
  vehicleLength: number;         // meters

  // MOBIL
  politenessFactor: number;      // p
  changingThreshold: number;     // delta_a_th, m/s²
  safeDeceleration: number;      // b_safe, m/s²

  // Road
  roadLengthMeters: number;
  laneCount: number;

  // Traffic demand
  spawnRate: number;             // vehicles per second

  // Simulation
  dt: number;                    // fixed timestep, seconds
  speedMultiplier: number;       // 1x, 2x, 5x, 10x
}

export interface VehicleState {
  id: number;
  x: number;
  laneIndex: number;
  speed: number;
  acceleration: number;
  length: number;
  desiredSpeed: number;
}

export interface IncidentConfig {
  id: number;
  positionX: number;
  lanesBlocked: number[];
  severity: number;              // 0-1
  startTime: number;
  duration: number;              // seconds, -1 for manual removal
  rubberneckingFactor: number;   // 0.5-1.0
}

export interface SimulationState {
  vehicles: VehicleState[];
  simulationTime: number;
}

export interface RoadSegmentData {
  segmentIndex: number;
  density: number;               // vehicles per km
  flow: number;                  // vehicles per hour
  averageSpeed: number;          // m/s
}

import type { SimulationParams } from './types';

export const DEFAULT_PARAMS: SimulationParams = {
  // IDM parameters
  desiredSpeed: 33.3,            // v0 = 120 km/h ≈ 33.3 m/s
  timeHeadway: 1.5,              // T = 1.5 seconds
  maxAcceleration: 1.0,          // a = 1.0 m/s²
  comfortDeceleration: 1.5,      // b = 1.5 m/s²
  minimumGap: 2.0,               // s0 = 2.0 meters
  vehicleLength: 5.0,            // 5.0 meters

  // MOBIL parameters
  politenessFactor: 0.5,         // p = 0.5
  changingThreshold: 0.2,        // delta_a_th = 0.2 m/s²
  safeDeceleration: 4.0,         // b_safe = 4.0 m/s²

  // Road parameters
  roadLengthMeters: 2000,        // 2 km road
  laneCount: 3,                  // 3 lanes

  // Traffic demand
  spawnRate: 0.5,                // 0.5 vehicles per second

  // Simulation
  dt: 1 / 60,                    // 60 fps fixed timestep
  speedMultiplier: 1,            // 1x real-time
};

