          speedHeatmap={
            <SpeedHeatmap
              history={heatmapHistory}
              maxSpeed={simulation.engine.current.params.desiredSpeed}
            />
          }
          flowTimeSeries={<FlowTimeSeries data={flowTimeSeries} />}
        />
      </main>
    </div>
  );
}

