  1→import { Road } from './Road';
  2→import { OnRamp } from './OnRamp';
  3→import { VehicleFactory } from './VehicleFactory';
  4→import { IncidentManager } from './incidents/IncidentManager';
  5→import { computeAcceleration } from './models/IDMModel';
  6→import { evaluateLaneChange } from './models/MOBILModel';
  7→import type { SimulationParams, SimulationState, VehicleState, IncidentConfig } from '../types';
  8→import { DEFAULT_PARAMS } from '../constants';
  9→
 10→export class SimulationEngine {
 11→  road: Road;
 12→  vehicleFactory: VehicleFactory;
 13→  incidentManager: IncidentManager;
 14→  params: SimulationParams;
 15→  simulationTime: number = 0;
 16→  private accumulator: number = 0;
 17→
 18→  constructor(params: SimulationParams = DEFAULT_PARAMS) {
 19→    this.params = { ...params };
 20→    this.road = new Road(params.roadLengthMeters, params.laneCount);
 21→    this.vehicleFactory = new VehicleFactory();
 22→    this.incidentManager = new IncidentManager();
 23→
 24→    // Default on-ramp at 1/3 of road length
 25→    const ramp = new OnRamp(Math.round(params.roadLengthMeters / 3));
 26→    this.road.addOnRamp(ramp);
 27→  }
 28→
 29→  addIncident(config: IncidentConfig) {
 30→    return this.incidentManager.addIncident(config);
 31→  }
 32→
 33→  removeIncident(id: number) {
 34→    this.incidentManager.removeIncident(id);
 35→  }
 36→
 37→  update(wallDeltaMs: number): void {
 38→    const dt = this.params.dt;
 39→    const scaledDelta = (wallDeltaMs / 1000) * this.params.speedMultiplier;
 40→    this.accumulator += scaledDelta;
 41→
 42→    // Cap accumulator to prevent spiral of death
 43→    if (this.accumulator > 0.5) {
 44→      this.accumulator = 0.5;
 45→    }
 46→
 47→    while (this.accumulator >= dt) {
 48→      this.step(dt);
 49→      this.accumulator -= dt;
 50→    }
 51→  }
 52→
 53→  step(dt: number): void {
 54→    // 1. Spawn vehicles
 55→    this.vehicleFactory.trySpawn(dt, this.road, this.params);
 56→
 57→    // 2. Compute IDM acceleration for each vehicle (with incident effects)
 58→    for (const lane of this.road.lanes) {
 59→      for (const vehicle of lane.vehicles) {
 60→        const actualLeader = this.road.getLeader(vehicle);
 61→        const virtualObstacle = this.incidentManager.getVirtualObstacle(vehicle);
 62→
 63→        // Use the closer of actual leader and virtual obstacle
 64→        let effectiveLeader = actualLeader;
 65→        if (virtualObstacle !== null) {
 66→          if (actualLeader === null || virtualObstacle.x < actualLeader.x) {
 67→            effectiveLeader = virtualObstacle;
 68→          }
 69→        }
 70→
 71→        const speedFactor = this.incidentManager.getSpeedReduction(vehicle);
 72→        vehicle.acceleration = computeAcceleration(
 73→          vehicle,
 74→          effectiveLeader,
 75→          this.params,
 76→          speedFactor,
 77→        );
 78→      }
 79→    }
 80→
 81→    // 3. MOBIL lane changes (shuffle order to avoid bias)
 82→    const allVehicles = this.road.getAllVehicles();
 83→    for (let i = allVehicles.length - 1; i > 0; i--) {
 84→      const j = Math.floor(Math.random() * (i + 1));
 85→      [allVehicles[i], allVehicles[j]] = [allVehicles[j], allVehicles[i]];
 86→    }
 87→
 88→    // Build set of blocked lanes from active incidents for MOBIL
 89→    const blockedLanes = new Set<number>();
 90→    for (const incident of this.incidentManager.getActiveIncidents()) {
 91→      for (const lane of incident.lanesBlocked) {
 92→        blockedLanes.add(lane);
 93→      }
