  1→import { useRef, useEffect, useCallback, useState } from 'react';
  2→import { Renderer } from './Renderer';
  3→import { IncidentPopover, IncidentList } from '../ui/IncidentControls';
  4→import type { IncidentConfig } from '../types';
  5→import type { useSimulation } from '../hooks/useSimulation';
  6→
  7→const LANE_WIDTH = 3.7;
  8→
  9→interface SimulationCanvasProps {
 10→  simulation: ReturnType<typeof useSimulation>;
 11→}
 12→
 13→export function SimulationCanvas({ simulation }: SimulationCanvasProps) {
 14→  const canvasRef = useRef<HTMLCanvasElement>(null);
 15→  const rendererRef = useRef<Renderer | null>(null);
 16→  const isDragging = useRef(false);
 17→  const dragMoved = useRef(false);
 18→  const lastMouse = useRef({ x: 0, y: 0 });
 19→  const {
 20→    state,
 21→    addIncident,
 22→    removeIncident,
 23→    getActiveIncidents,
 24→    engine: engineRef,
 25→  } = simulation;
 26→
 27→  const [popover, setPopover] = useState<{
 28→    positionX: number;
 29→    screenX: number;
 30→    screenY: number;
 31→  } | null>(null);
 32→
 33→  const [, setIncidentVersion] = useState(0);
 34→
 35→  // Initialize renderer
 36→  useEffect(() => {
 37→    const canvas = canvasRef.current;
 38→    if (!canvas) return;
 39→
 40→    const rect = canvas.getBoundingClientRect();
 41→    canvas.width = rect.width * devicePixelRatio;
 42→    canvas.height = rect.height * devicePixelRatio;
 43→
 44→    rendererRef.current = new Renderer(canvas);
 45→  }, []);
 46→
 47→  // Handle resize
 48→  useEffect(() => {
 49→    const canvas = canvasRef.current;
 50→    if (!canvas) return;
 51→
 52→    const observer = new ResizeObserver((entries) => {
 53→      for (const entry of entries) {
 54→        const { width, height } = entry.contentRect;
 55→        canvas.width = width * devicePixelRatio;
 56→        canvas.height = height * devicePixelRatio;
 57→        rendererRef.current?.getCamera().resize(canvas.width, canvas.height);
 58→      }
 59→    });
 60→    observer.observe(canvas);
 61→    return () => observer.disconnect();
 62→  }, []);
 63→
 64→  // Draw on state change
 65→  useEffect(() => {
 66→    rendererRef.current?.draw(state, getActiveIncidents(), engineRef.current.road.onRamps);
 67→  }, [state, getActiveIncidents]);
 68→
 69→  const onMouseDown = useCallback((e: React.MouseEvent) => {
 70→    isDragging.current = true;
 71→    dragMoved.current = false;
 72→    lastMouse.current = { x: e.clientX, y: e.clientY };
 73→  }, []);
 74→
 75→  const onMouseMove = useCallback((e: React.MouseEvent) => {
 76→    if (!isDragging.current) return;
 77→    const dx = (e.clientX - lastMouse.current.x) * devicePixelRatio;
 78→    const dy = (e.clientY - lastMouse.current.y) * devicePixelRatio;
 79→    if (Math.abs(dx) > 2 || Math.abs(dy) > 2) {
 80→      dragMoved.current = true;
 81→    }
 82→    rendererRef.current?.getCamera().handlePan(dx, dy);
 83→    lastMouse.current = { x: e.clientX, y: e.clientY };
 84→  }, []);
 85→
 86→  const onMouseUp = useCallback(
 87→    (e: React.MouseEvent) => {
 88→      const wasDragging = dragMoved.current;
 89→      isDragging.current = false;
 90→      dragMoved.current = false;
 91→
 92→      if (wasDragging || !rendererRef.current) return;
 93→
 94→      const canvas = canvasRef.current;
 95→      if (!canvas) return;
 96→
 97→      const rect = canvas.getBoundingClientRect();
 98→      const sx = (e.clientX - rect.left) * devicePixelRatio;
 99→      const sy = (e.clientY - rect.top) * devicePixelRatio;
100→      const world = rendererRef.current.getCamera().screenToWorld(sx, sy);
101→
102→      const params = engineRef.current.params;
103→      const roadHeight = params.laneCount * LANE_WIDTH;
104→      if (
105→        world.x >= 0 &&
106→        world.x <= params.roadLengthMeters &&
107→        world.y >= 0 &&
108→        world.y <= roadHeight
109→      ) {
110→        setPopover({
111→          positionX: world.x,
112→          screenX: e.clientX - rect.left,
113→          screenY: e.clientY - rect.top,
114→        });
115→      } else {
116→        setPopover(null);
117→      }
118→    },
119→    [engineRef],
120→  );
121→
122→  const onMouseLeave = useCallback(() => {
123→    isDragging.current = false;
124→    dragMoved.current = false;
125→  }, []);
126→
127→  const onWheel = useCallback((e: React.WheelEvent) => {
128→    e.preventDefault();
129→    const rect = canvasRef.current?.getBoundingClientRect();
130→    if (!rect) return;
131→    const x = (e.clientX - rect.left) * devicePixelRatio;
132→    const y = (e.clientY - rect.top) * devicePixelRatio;
133→    rendererRef.current?.getCamera().handleZoom(-e.deltaY, x, y);
134→  }, []);
135→
136→  const handleCreateIncident = useCallback(
137→    (config: IncidentConfig) => {
138→      addIncident(config);
139→      setPopover(null);
140→      setIncidentVersion((v) => v + 1);
141→    },
142→    [addIncident],
143→  );
144→
145→  const handleRemoveIncident = useCallback(
146→    (id: number) => {
147→      removeIncident(id);
148→      setIncidentVersion((v) => v + 1);
149→    },
150→    [removeIncident],
151→  );
152→
153→  const incidents = getActiveIncidents();
154→  const params = engineRef.current.params;
155→
156→  return (
157→    <div className="relative h-full">
158→      <canvas
159→        ref={canvasRef}
160→        className="w-full h-full"
161→        onMouseDown={onMouseDown}
162→        onMouseMove={onMouseMove}
163→        onMouseUp={onMouseUp}
164→        onMouseLeave={onMouseLeave}
165→        onWheel={onWheel}
166→      />
167→      {popover && (
168→        <IncidentPopover
169→          positionX={popover.positionX}
170→          screenX={popover.screenX}
171→          screenY={popover.screenY}
172→          laneCount={params.laneCount}
173→          simulationTime={state.simulationTime}
174→          onCreat={handleCreateIncident}
175→          onCancel={() => setPopover(null)}
176→        />
177→      )}
178→      <IncidentList incidents={incidents} onRemove={handleRemoveIncident} />
179→    </div>
180→  );
181→}
182→

